# Write-Behind Save System
_dirty_users: set = set()
_dirty_lock = asyncio.Lock()
_save_executor = concurrent.futures.ThreadPoolExecutor(
    max_workers=4, thread_name_prefix="disk_writer"
)

# Wallet-level async locks to prevent double-spend races
_wallet_locks: dict = {}

def _get_wallet_lock(user_id: int) -> asyncio.Lock:
    if user_id not in _wallet_locks:
        _wallet_locks[user_id] = asyncio.Lock()
    return _wallet_locks[user_id]

# Banned/Tempbanned set caches
_banned_set: set = set()
_tempbanned_set: set = set()

def _rebuild_ban_sets():
    global _banned_set, _tempbanned_set
    _banned_set = set(bot_settings.get("banned_users", []))
    _tempbanned_set = set(bot_settings.get("tempbanned_users", []))

def ban_user(user_id: int):
    bot_settings.setdefault("banned_users", [])
    if user_id not in bot_settings["banned_users"]:
        bot_settings["banned_users"].append(user_id)
    _banned_set.add(user_id)

def unban_user(user_id: int):
    bot_settings["banned_users"] = [u for u in bot_settings.get("banned_users", []) if u != user_id]
    _banned_set.discard(user_id)

def tempban_user(user_id: int):
    bot_settings.setdefault("tempbanned_users", [])
    if user_id not in bot_settings["tempbanned_users"]:
        bot_settings["tempbanned_users"].append(user_id)
    _tempbanned_set.add(user_id)

def untempban_user(user_id: int):
    bot_settings["tempbanned_users"] = [u for u in bot_settings.get("tempbanned_users", []) if u != user_id]
    _tempbanned_set.discard(user_id)

