async def generate_stats_image(user_id: int, context: ContextTypes.DEFAULT_TYPE, period='all_time'):
    """Generate stats template image with profile picture support."""
    try:
        stats = user_stats.get(user_id, {})
        userinfo = stats.get('userinfo', {})
        first_name = userinfo.get('first_name', 'User')
        username = userinfo.get('username', '')
        join_date = userinfo.get('join_date', 'N/A')

        global _bot_username_cache
        if _bot_username_cache is None:
            bot_info = await context.bot.get_me()
            _bot_username_cache = bot_info.username
        bot_username = _bot_username_cache

        # Fetch profile picture
        profile_pic = await _get_cached_profile_picture(context, user_id)

        # Format member since
        member_since = 'N/A'
        if join_date != 'N/A':
            try:
                date_obj = datetime.fromisoformat(join_date.replace('Z', '+00:00'))
                member_since = date_obj.strftime('%d %b %Y')
            except (ValueError, AttributeError):
                member_since = join_date[:10]

        # Calculate stats
        if period == '24h':
            now = datetime.now(timezone.utc)
            cutoff = now - timedelta(hours=24)
            user_game_ids = stats.get("game_sessions", [])
            total_games = wins = losses = 0
            total_wagered = total_pnl = 0.0
            game_breakdown = {}
            biggest_win = 0.0
            biggest_win_game = ''

            for gid in user_game_ids:
                game = game_sessions.get(gid)
                if not game:
                    continue
                try:
                    ts = game.get("timestamp", "")
                    game_time = datetime.fromisoformat(ts.replace('Z', '+00:00')) if ts else None
                    if game_time and game_time >= cutoff:
                        total_games += 1
                        bet_amt = game.get("bet_amount", 0.0)
                        total_wagered += bet_amt
                        profit = game.get("profit", 0.0)
                        total_pnl += profit
                        gtype = game.get("game_type", "Unknown")
                        if gtype not in game_breakdown:
                            game_breakdown[gtype] = {"games": 0, "wins": 0, "wagered": 0.0, "pnl": 0.0}
                        game_breakdown[gtype]["games"] += 1
                        game_breakdown[gtype]["wagered"] += bet_amt
                        game_breakdown[gtype]["pnl"] += profit
                        if game.get("win") is True:
                            wins += 1
                            game_breakdown[gtype]["wins"] += 1
                            if profit > biggest_win:
                                biggest_win = profit
                                biggest_win_game = gtype
                        elif game.get("win") is False:
                            losses += 1
                except (ValueError, TypeError):
                    continue
            win_rate = (wins / total_games * 100) if total_games > 0 else 0
        else:
            total_bets = stats.get('bets', {}).get('count', 0)
            wins = stats.get('bets', {}).get('wins', 0)
            losses = stats.get('bets', {}).get('losses', 0)
            total_games = total_bets
            total_wagered = stats.get('bets', {}).get('amount', 0.0)
            win_rate = (wins / total_bets * 100) if total_bets > 0 else 0
            total_pnl = stats.get('pnl', 0.0)
            game_breakdown = {}
            history = stats.get('bets', {}).get('history', [])
            biggest_win = 0.0
            biggest_win_game = ''
            for bet in history[-500:]:
                gtype = bet.get('game_type', 'Unknown')
                if gtype not in game_breakdown:
                    game_breakdown[gtype] = {"games": 0, "wins": 0, "wagered": 0.0, "pnl": 0.0}
                game_breakdown[gtype]["games"] += 1
                game_breakdown[gtype]["wagered"] += bet.get('bet_amount', 0.0)
                profit = bet.get('profit', 0.0)
                game_breakdown[gtype]["pnl"] += profit
                if bet.get('win') is True:
                    game_breakdown[gtype]["wins"] += 1
                    if profit > biggest_win:
                        biggest_win = profit
                        biggest_win_game = gtype

        # Favorite game = most wagered (not most played)
        fav_game = 'N/A'
        if game_breakdown:
            fav_game = max(game_breakdown.items(), key=lambda x: x[1]["wagered"])[0]
        avg_bet = (total_wagered / total_games) if total_games > 0 else 0
        total_bonuses = stats.get('rakeback_balance', 0.0)
        level_data = get_user_level(user_id)

        # PvP data
        pvp_wins = stats.get('bets', {}).get('pvp_wins', 0)
        pvp_entries = []
        if pvp_wins > 0:
            pvp_entries.append({"name": "Emoji PvP", "games": pvp_wins, "pnl": f"-${total_pnl * 0.1:.2f}"})

        # Game type display name mapping
        GAME_DISPLAY_NAMES = {
            "dice": "Dice", "darts": "Darts", "goal": "Goal", "bowl": "Bowling",
            "blackjack": "Blackjack", "coinflip": "Coinflip", "roulette": "Roulette",
            "slots": "Slots", "keno": "Keno", "tower": "Tower", "highlow": "HighLow",
            "limbo": "Limbo", "predict": "Predict", "crash": "Crash", "plinko": "Plinko",
            "wheel": "Wheel", "scratch": "Scratch", "coinchain": "Coinchain", "mines": "Mines",
            "7up7down": "7Up7Down", "7up7down_original": "7Up7Down",
            "dicerush": "Dicerush", "dicerush_original": "Dicerush",
            "rush_rainbow": "Rush_Rainbow", "rush_rainbow_original": "Rush_Rainbow",
            "hi_lo": "HiLo", "aviator": "Aviator", "jetx": "JetX",
            "poker": "Poker", "baccarat": "Baccarat", "teenpatti": "Teen Patti",
            "andarbahar": "Andar Bahar", "dragon_tiger": "Dragon Tiger",
        }

        def get_display_name(internal_name):
            """Convert internal game type to display name."""
            clean = internal_name.replace("pvb_", "").replace("xdxw_", "").replace("_original", "").lower()
            return GAME_DISPLAY_NAMES.get(clean, internal_name.replace("_", " ").title())

        sorted_games = sorted(game_breakdown.items(), key=lambda x: x[1]["games"], reverse=True)[:8]
        game_list = []
        for gname, gdata in sorted_games:
            ggames = gdata["games"]
            gwr = (gdata["wins"] / ggames * 100) if ggames > 0 else 0
            gpnl = gdata["pnl"]
            display_name = get_display_name(gname)
            game_list.append({"name": display_name, "games": ggames, "wr": gwr, "pnl": gpnl, "pnl_positive": gpnl >= 0})

        # Calculate rank from all-time leaderboard
        user_rank = None
        for idx, (lb_uid, lb_uname, lb_wagered) in enumerate(leaderboard_data.get("all_time", [])):
            if lb_uid == user_id:
                user_rank = idx + 1
                break
        rank_str = f"#{user_rank}" if user_rank else "#---"

        text_data = {
            "first_name": first_name,
            "username": f"@{username}" if username else "@user",
            "user_id": str(user_id),
            "level": level_data['name'],
            "rank": rank_str,
            "member_since": member_since,
            "bot_username": bot_username,
            "period_label": "30d",
            "total_games": total_games,
            "total_wagered": total_wagered,
            "total_pnl": total_pnl,
            "pnl_positive": total_pnl >= 0,
            "win_rate": win_rate,
            "avg_bet": avg_bet,
            "biggest_win": biggest_win,
            "biggest_win_game": biggest_win_game,
            "total_bonuses": total_bonuses,
            "fav_game": fav_game,
        }

        loop = asyncio.get_running_loop()
        result = await loop.run_in_executor(
            _image_executor,
            _render_stats_sync,
            text_data,
            game_list,
            pvp_entries,
            profile_pic,
        )
        return result
    except Exception as e:
        logging.error(f"Error generating stats image: {e}")
        return None


def _render_stats_sync(text_data, game_list, pvp_entries, profile_pic_data):
    """Render stats template with fixed grid layout - no overlapping."""
    try:
        W, H = 700, 1100
        img = Image.new('RGBA', (W, H), (10, 15, 25))
        draw = ImageDraw.Draw(img)

        # Load fonts
        try:
            f_title = ImageFont.truetype("bold.ttf", 24)
            f_stat_val = ImageFont.truetype("bold.ttf", 20)
            f_stat_lbl = ImageFont.truetype("bold.ttf", 10)
            f_pnl = ImageFont.truetype("bold.ttf", 14)
            f_detail = ImageFont.truetype("bold.ttf", 12)
            f_bonus = ImageFont.truetype("bold.ttf", 14)
            f_game_name = ImageFont.truetype("bold.ttf", 12)
            f_game_val = ImageFont.truetype("bold.ttf", 11)
            f_rank_big = ImageFont.truetype("bold.ttf", 28)
            f_level = ImageFont.truetype("bold.ttf", 13)
        except Exception:
            f_title = f_stat_val = f_stat_lbl = f_pnl = f_detail = f_bonus = f_game_name = f_game_val = f_rank_big = f_level = ImageFont.load_default()

        # --- Background stars ---
        rng = random.Random(42)
        for _ in range(80):
            sx = rng.randint(0, W)
            sy = rng.randint(0, H)
            sr = rng.randint(1, 2)
            draw.ellipse([sx - sr, sy - sr, sx + sr, sy + sr], fill=(255, 255, 255, rng.randint(80, 200)))

        # --- Top bar ---
        draw.rounded_rectangle([0, 0, W, 56], radius=0, fill=(12, 18, 32))
        draw.line([(0, 56), (W, 56)], fill=(40, 60, 90), width=1)

        # Period badge (top left)
        badge_text = text_data["period_label"].upper()
        badge_w = draw.textlength(badge_text, font=f_detail)
        badge_rect = [15, 14, 15 + badge_w + 16, 14 + 28]
        draw.rounded_rectangle(badge_rect, radius=6, outline=(100, 200, 255), width=1, fill=(20, 40, 60))
        draw.text((15 + 8, 14 + 4), badge_text, fill=(100, 200, 255), font=f_detail)

        # Bot username (top right)
        bot_un = f"@{text_data['bot_username']}"
        bot_w = draw.textlength(bot_un, font=f_detail)
        draw.text((W - 15 - bot_w, 18), bot_un, fill=(100, 200, 255), font=f_detail)

        # --- Profile section ---
        avatar_x, avatar_y = 35, 80
        avatar_r = 32

        # Draw profile picture with circular mask
        if profile_pic_data and isinstance(profile_pic_data, Image.Image):
            try:
                pic = profile_pic_data.convert("RGBA").resize((avatar_r * 2, avatar_r * 2), Image.Resampling.LANCZOS)
                mask = Image.new("L", (avatar_r * 2, avatar_r * 2), 0)
                ImageDraw.Draw(mask).ellipse((0, 0, avatar_r * 2 - 1, avatar_r * 2 - 1), fill=255)
                circ = Image.new("RGBA", (avatar_r * 2, avatar_r * 2), (0, 0, 0, 0))
                circ.paste(pic, (0, 0), mask)
                img.paste(circ, (avatar_x - avatar_r, avatar_y - avatar_r), circ)
            except Exception:
                draw.ellipse([avatar_x - avatar_r, avatar_y - avatar_r, avatar_x + avatar_r, avatar_y + avatar_r],
                             fill=(30, 50, 80), outline=(100, 200, 255), width=2)
        else:
            draw.ellipse([avatar_x - avatar_r, avatar_y - avatar_r, avatar_x + avatar_r, avatar_y + avatar_r],
                         fill=(30, 50, 80), outline=(100, 200, 255), width=2)

        # Name and username next to avatar
        name_x = avatar_x + avatar_r + 15
        name_y = avatar_y - 12
        draw.text((name_x, name_y), text_data["first_name"], fill=(255, 255, 255), font=f_title)
        draw.text((name_x, name_y + 26), text_data["username"], fill=(150, 180, 220), font=f_detail)

        # User ID and Member since below name
        id_text = f"ID: {text_data['user_id']}"
        ms_text = f"Joined: {text_data['member_since']}"
        draw.text((name_x, name_y + 50), id_text, fill=(120, 140, 170), font=ImageFont.load_default())
        draw.text((name_x + 120, name_y + 50), ms_text, fill=(120, 140, 170), font=ImageFont.load_default())

        # Rank badge (top right of profile section)
        rank_text = text_data["rank"]
        rank_w = draw.textlength(rank_text, font=f_rank_big)
        rank_box = [W - 120, 72, W - 120 + rank_w + 24, 72 + 40]
        draw.rounded_rectangle(rank_box, radius=8, fill=(25, 35, 55), outline=(255, 200, 50), width=2)
        draw.text((W - 120 + 12, 72 + 4), rank_text, fill=(255, 200, 50), font=f_rank_big)

        # Level badge below rank
        lvl_text = text_data["level"]
        lvl_w = draw.textlength(lvl_text, font=f_level)
        lvl_box = [W - 120, 118, W - 120 + lvl_w + 16, 118 + 22]
        draw.rounded_rectangle(lvl_box, radius=6, fill=(40, 20, 60), outline=(180, 100, 255), width=1)
        draw.text((W - 120 + 8, 118 + 2), lvl_text, fill=(180, 130, 255), font=f_level)

        # --- Stat boxes: fixed grid layout ---
        box_w, box_h = 155, 72
        gap = 10
        start_x = 25
        y_row1 = 150
        y_row2 = y_row1 + box_h + gap + 10

        # Row 1: Total Games, Total Wagered, Win Rate
        stats_row1 = [
            (f'{text_data["total_games"]}', 'GAMES PLAYED', (255, 255, 255)),
            (f'${text_data["total_wagered"]:,.2f}', 'TOTAL WAGERED', (100, 200, 255)),
            (f'{text_data["win_rate"]:.1f}%', 'WIN RATE', (255, 200, 50)),
        ]
        for i, (val, lbl, color) in enumerate(stats_row1):
            bx = start_x + i * (box_w + gap)
            draw.rounded_rectangle([bx, y_row1, bx + box_w, y_row1 + box_h], radius=10, fill=(15, 22, 38), outline=(40, 60, 90), width=1)
            # Value
            draw.text((bx + 10, y_row1 + 8), val, fill=color, font=f_stat_val)
            # Label
            draw.text((bx + 10, y_row1 + 42), lbl, fill=(120, 140, 170), font=f_stat_lbl)

        # Row 2: Total PnL, Avg Bet, Biggest Win
        pnl_val = text_data["total_pnl"]
        pnl_color = (80, 220, 120) if pnl_val >= 0 else (255, 80, 80)
        pnl_sign = "+" if pnl_val >= 0 else ""
        stats_row2 = [
            (f'{pnl_sign}${pnl_val:,.2f}', 'TOTAL P&L', pnl_color),
            (f'${text_data["avg_bet"]:,.2f}', 'AVG BET SIZE', (100, 200, 255)),
            (f'+${text_data["biggest_win"]:,.2f}', f'BIGGEST WIN ({text_data["biggest_win_game"]})', (255, 200, 50)),
        ]
        for i, (val, lbl, color) in enumerate(stats_row2):
            bx = start_x + i * (box_w + gap)
            draw.rounded_rectangle([bx, y_row2, bx + box_w, y_row2 + box_h], radius=10, fill=(15, 22, 38), outline=(40, 60, 90), width=1)
            draw.text((bx + 10, y_row2 + 8), val, fill=color, font=f_pnl if 'P&L' in lbl or 'WIN' in lbl else f_stat_val)
            draw.text((bx + 10, y_row2 + 42), lbl, fill=(120, 140, 170), font=f_stat_lbl)

        # --- Favorite Game & Bonus Rakeback section ---
        y_extra = y_row2 + box_h + 15
        draw.rounded_rectangle([25, y_extra, 340, y_extra + 40], radius=8, fill=(15, 22, 38), outline=(40, 60, 90), width=1)
        draw.text((35, y_extra + 5), "FAVORITE GAME", fill=(100, 140, 170), font=f_stat_lbl)
        draw.text((35, y_extra + 20), text_data["fav_game"], fill=(255, 200, 50), font=f_detail)

        bonus_val = text_data["total_bonuses"]
        draw.rounded_rectangle([350, y_extra, W - 25, y_extra + 40], radius=8, fill=(20, 15, 35), outline=(180, 100, 255), width=1)
        draw.text((360, y_extra + 5), "BONUS RAKEBACK", fill=(140, 100, 200), font=f_stat_lbl)
        draw.text((360, y_extra + 20), f"${bonus_val:,.2f}", fill=(180, 130, 255), font=f_bonus)

        # --- Games Breakdown section ---
        y_games = y_extra + 55
        draw.line([(25, y_games), (W - 25, y_games)], fill=(40, 60, 90), width=1)
        draw.text((25, y_games + 5), "GAMES BREAKDOWN", fill=(100, 200, 255), font=f_detail)

        y_games += 30
        for g in game_list:
            gname = g["name"]
            ggames = g["games"]
            gwr = g["wr"]
            gpnl = g["pnl"]
            gpnl_pos = g["pnl_positive"]
            gpnl_color = (80, 220, 120) if gpnl_pos else (255, 80, 80)
            gpnl_sign = "+" if gpnl_pos else ""

            row_h = 30
            draw.rounded_rectangle([25, y_games, W - 25, y_games + row_h], radius=6, fill=(15, 22, 38))

            draw.text((35, y_games + 7), gname, fill=(255, 255, 255), font=f_game_name)
            draw.text((180, y_games + 7), f"{ggames} games", fill=(120, 140, 170), font=f_game_val)
            draw.text((290, y_games + 7), f"{gwr:.1f}% WR", fill=(255, 200, 50), font=f_game_val)
            draw.text((W - 35, y_games + 7), f"{gpnl_sign}${gpnl:,.2f}", fill=gpnl_color, font=f_game_val, anchor="ra")

            y_games += row_h + 4

        # --- PvP section ---
        if pvp_entries:
            y_pvp = y_games + 10
            draw.line([(25, y_pvp), (W - 25, y_pvp)], fill=(40, 60, 90), width=1)
            draw.text((25, y_pvp + 5), "PVP STATS", fill=(255, 100, 100), font=f_detail)
            y_pvp += 30
            for pvp in pvp_entries:
                row_h = 30
                draw.rounded_rectangle([25, y_pvp, W - 25, y_pvp + row_h], radius=6, fill=(25, 15, 15))
                draw.text((35, y_pvp + 7), pvp["name"], fill=(255, 255, 255), font=f_game_name)
                draw.text((180, y_pvp + 7), f'{pvp["games"]} wins', fill=(100, 255, 100), font=f_game_val)
                draw.text((W - 35, y_pvp + 7), pvp["pnl"], fill=(255, 80, 80), font=f_game_val, anchor="ra")
                y_pvp += row_h + 4

        # Save
        from io import BytesIO
        buf = BytesIO()
        img.save(buf, format='PNG')
        buf.seek(0)
        return buf
    except Exception as e:
        logging.error(f"Error rendering stats image: {e}")
        return None


# ============================================================
# LEADERBOARD TEMPLATE - 1:1 copy of example design
# ============================================================
async def generate_leaderboard_image(context, period='all_time'):
    """Generate leaderboard template image - exact 1:1 copy of the example template."""
    try:
        global _bot_username_cache
        if _bot_username_cache is None:
            bot_info = await context.bot.get_me()
            _bot_username_cache = bot_info.username
        bot_username = _bot_username_cache

        # Map period to data key and title
        period_map = {
            'all_time': ('all_time', 'All-Time Top Wagered'),
            'weekly': ('weekly', 'Weekly Top Wagered'),
            'monthly': ('monthly', 'Monthly Top Wagered'),
            'highest_wins': ('highest_wins', 'Highest Wins - This Month'),
        }
        data_key, section_title = period_map.get(period, ('all_time', 'All-Time Top Wagered'))
        data = leaderboard_data.get(data_key, [])

        entries = []
        if data_key == 'highest_wins':
            for i, (uid, uname, wamt, gtype, ts) in enumerate(data[:10]):
                entries.append({"rank": i + 1, "username": uname, "value": wamt})
        else:
            for i, (uid, uname, wagered) in enumerate(data[:10]):
                entries.append({"rank": i + 1, "username": uname, "value": wagered})

        loop = asyncio.get_running_loop()
        result = await loop.run_in_executor(
            _image_executor,
            _render_leaderboard_sync,
            entries,
            bot_username,
            section_title,
        )
        return result
    except Exception as e:
        logging.error(f"Error generating leaderboard image: {e}")
        return None


def _render_leaderboard_sync(entries, bot_username, section_title):
    """Render leaderboard template - 1:1 copy of example design."""
    try:
        W, H = 700, 1050
        # Background: dark blue with stars
        img = Image.new("RGB", (W, H), (10, 28, 45))
        draw = ImageDraw.Draw(img)

        import random
        rng = random.Random(42)
        for _ in range(60):
            sx = rng.randint(0, W)
            sy = rng.randint(0, H)
            sr = rng.randint(1, 2)
            draw.ellipse([sx - sr, sy - sr, sx + sr, sy + sr], fill=(255, 255, 255, 150))

        try:
            f_title = ImageFont.truetype("bold.ttf", 26)
            f_med = ImageFont.truetype("bold.ttf", 22)
            f_reg = ImageFont.truetype("bold.ttf", 18)
            f_small = ImageFont.truetype("bold.ttf", 15)
            f_xsmall = ImageFont.truetype("bold.ttf", 12)
            f_val = ImageFont.truetype("bold.ttf", 20)
            f_rank = ImageFont.truetype("bold.ttf", 28)
            f_section = ImageFont.truetype("bold.ttf", 18)
            f_col_header = ImageFont.truetype("bold.ttf", 11)
            f_big_rank = ImageFont.truetype("bold.ttf", 32)
        except Exception:
            f_title = f_med = f_reg = f_small = f_xsmall = f_val = f_rank = f_section = f_col_header = f_big_rank = ImageFont.load_default()

        y = 18

        # Trophy icon - use text-based trophy since bold.ttf doesn't support emoji
        trophy = "\U0001F3C6"
        try:
            trophy_font = ImageFont.truetype("NotoColorEmoji.ttf", 28)
            tw2 = draw.textlength(trophy, font=trophy_font)
            draw.text(((W - tw2) // 2, y), trophy, fill=(255, 200, 100), font=trophy_font)
        except Exception:
            # Fallback: draw a simple trophy shape
            trophy_cx = W // 2
            trophy_cy = y + 14
            # Cup body
            draw.ellipse([trophy_cx - 14, trophy_cy - 10, trophy_cx + 14, trophy_cy + 10], fill=(255, 200, 100))
            draw.rectangle([trophy_cx - 3, trophy_cy + 8, trophy_cx + 3, trophy_cy + 18], fill=(255, 200, 100))
            draw.rectangle([trophy_cx - 10, trophy_cy + 16, trophy_cx + 10, trophy_cy + 18], fill=(255, 200, 100))
        y += 30

        # Bot username top right (no tagline below)
        bot_un = f"@{bot_username}"
        bw = draw.textlength(bot_un, font=f_med)
        draw.text((W - 15 - bw, y), bot_un, fill=(255, 200, 50), font=f_med)
        y += 30

        # Title: "PlayCasino Leaderboard" with decorative lines
        full_title = "PlayCasino Leaderboard"
        ftw = draw.textlength(full_title, font=f_title)
        title_x = (W - ftw) // 2
        # Left decorative line
        draw.line([(title_x - 60, y + 12), (title_x - 15, y + 12)], fill=(100, 200, 255), width=2)
        draw.text((title_x, y), full_title, fill=(255, 255, 255), font=f_title)
        # Right decorative line
        draw.line([(title_x + ftw + 15, y + 12), (title_x + ftw + 60, y + 12)], fill=(100, 200, 255), width=2)
        y += 42

        # Section title box: "💰 All-Time Top Wagered"
        draw.rounded_rectangle([20, y, W - 20, y + 34], radius=8, outline=(100, 200, 255), width=2, fill=(15, 40, 60))
        draw.text((40, y + 6), f"💰 {section_title}", fill=(100, 200, 255), font=f_section)
        y += 44

        # Column headers
        draw.text((50, y), "RANK", fill=(150, 150, 150), font=f_col_header)
        draw.text((110, y), "PLAYER", fill=(150, 150, 150), font=f_col_header)
        draw.text((W - 30, y), "WAGERED", fill=(150, 150, 150), font=f_col_header, anchor="ra")
        y += 20

        # Entry rows
        medals = ["\U0001F947", "\U0001F948", "\U0001F949"]
        medal_colors = [(255, 200, 50), (180, 180, 180), (205, 127, 50)]
        medal_nums = ["1", "2", "3"]

        for i, entry in enumerate(entries):
            row_h = 42
            rank = entry["rank"]
            uname = entry["username"]
            if len(uname) > 20:
                uname = uname[:17] + "..."
            val = entry["value"]

            # Row background
            if rank == 1:
                row_color = (40, 55, 25)
                draw.rounded_rectangle([20, y, W - 20, y + row_h], radius=10, outline=(255, 200, 50), width=2, fill=row_color)
            elif rank == 2:
                row_color = (25, 40, 55)
                draw.rounded_rectangle([20, y, W - 20, y + row_h], radius=10, fill=row_color)
            elif rank == 3:
                row_color = (35, 30, 40)
                draw.rounded_rectangle([20, y, W - 20, y + row_h], radius=10, fill=row_color)
            else:
                row_color = (20, 35, 50) if i % 2 == 0 else (18, 32, 45)
                draw.rounded_rectangle([20, y, W - 20, y + row_h], radius=8, fill=row_color)

            # Rank/Medal
            if rank <= 3:
                # Medal + rank number
                draw.text((35, y + 6), medals[rank - 1], fill=medal_colors[rank - 1], font=f_med)
            else:
                draw.text((38, y + 8), f"#{rank}", fill=(150, 150, 150), font=f_reg)

            # Username
            draw.text((110, y + 10), uname, fill=(255, 255, 255), font=f_reg)

            # Value with $ symbol
            val_str = f"${val:,.2f}"
            vw = draw.textlength(val_str, font=f_val)
            draw.text((W - 30, y + 10), val_str, fill=(100, 255, 100), font=f_val, anchor="ra")

            y += row_h + 4

        # If no entries
        if not entries:
            draw.text((W // 2 - 60, y), "No data yet", fill=(150, 150, 150), font=f_reg)
            y += 30

        # === Your Rank box ===
        y += 10
        draw.rounded_rectangle([20, y, W - 20, y + 55], radius=12, outline=(100, 200, 255), width=2, fill=(15, 40, 60))

        # Rank number box (gold)
        draw.rounded_rectangle([35, y + 10, 110, y + 45], radius=8, fill=(50, 45, 20), outline=(255, 200, 50), width=2)
        draw.text((52, y + 13), "#---", fill=(255, 200, 50), font=f_big_rank)

        draw.text((125, y + 10), "Your Rank", fill=(150, 200, 150), font=f_xsmall)
        draw.text((125, y + 28), "$0.00 wagered", fill=(100, 255, 100), font=f_small)

        y += 70
        # Play responsibly
        draw.text(((W - 110) // 2, y), "Play responsibly", fill=(100, 100, 100), font=f_xsmall)

        output = BytesIO()
        img.save(output, format='JPEG', quality=92)
        output.seek(0)
        return output
    except Exception as e:
        logging.error(f"PIL leaderboard render error: {e}")
        import traceback
        traceback.print_exc()
        return None


# ============================================================
# LEADERBOARD REFERRAL TEMPLATE
# ============================================================
async def generate_leaderboard_referral_image(context):
    """Generate referral leaderboard template - following same design language."""
    try:
        global _bot_username_cache
        if _bot_username_cache is None:
            bot_info = await context.bot.get_me()
            _bot_username_cache = bot_info.username
        bot_username = _bot_username_cache

        sorted_users = sorted(user_stats.items(), key=lambda item: len(item[1].get('referral', {}).get('referred_users', [])), reverse=True)

        entries = []
        for i, (uid, st) in enumerate(sorted_users[:10]):
            uname = st.get('userinfo', {}).get('username', f'User-{uid}').lstrip('@')
            rc = len(st.get('referral', {}).get('referred_users', []))
            if rc > 0:
                entries.append({"rank": len(entries) + 1, "username": uname, "referrals": rc})

        loop = asyncio.get_running_loop()
        result = await loop.run_in_executor(
            _image_executor,
            _render_leaderboard_referral_sync,
            entries,
            bot_username,
        )
        return result
    except Exception as e:
        logging.error(f"Error generating referral leaderboard image: {e}")
        return None


def _render_leaderboard_referral_sync(entries, bot_username):
    """Render referral leaderboard template."""
    try:
        W, H = 700, 750
        img = Image.new("RGB", (W, H), (10, 28, 45))
        draw = ImageDraw.Draw(img)

        import random
        rng = random.Random(42)
        for _ in range(60):
            sx = rng.randint(0, W)
            sy = rng.randint(0, H)
            sr = rng.randint(1, 2)
            draw.ellipse([sx - sr, sy - sr, sx + sr, sy + sr], fill=(255, 255, 255, 150))

        try:
            f_title = ImageFont.truetype("bold.ttf", 26)
            f_med = ImageFont.truetype("bold.ttf", 22)
            f_reg = ImageFont.truetype("bold.ttf", 18)
            f_small = ImageFont.truetype("bold.ttf", 15)
            f_xsmall = ImageFont.truetype("bold.ttf", 12)
            f_val = ImageFont.truetype("bold.ttf", 20)
            f_section = ImageFont.truetype("bold.ttf", 18)
            f_col_header = ImageFont.truetype("bold.ttf", 11)
            f_big_rank = ImageFont.truetype("bold.ttf", 32)
        except Exception:
            f_title = f_med = f_reg = f_small = f_xsmall = f_val = f_section = f_col_header = f_big_rank = ImageFont.load_default()

        y = 18

        # Draw trophy icon using PIL shapes (emoji won't render in PIL)
        trophy_cx, trophy_cy = W // 2, y + 12
        # Trophy cup
        draw.ellipse([trophy_cx - 14, trophy_cy - 14, trophy_cx + 14, trophy_cy + 8], outline=(255, 200, 100), width=2, fill=(60, 50, 20))
        # Handles
        draw.arc([trophy_cx - 22, trophy_cy - 10, trophy_cx - 6, trophy_cy + 8], 90, 270, fill=(255, 200, 100), width=2)
        draw.arc([trophy_cx + 6, trophy_cy - 10, trophy_cx + 22, trophy_cy + 8], -90, 90, fill=(255, 200, 100), width=2)
        # Base
        draw.rectangle([trophy_cx - 6, trophy_cy + 8, trophy_cx + 6, trophy_cy + 16], fill=(255, 200, 100))
        draw.rectangle([trophy_cx - 10, trophy_cy + 14, trophy_cx + 10, trophy_cy + 18], fill=(255, 200, 100))
        y += 32

        # Bot username (no tagline below)
        bot_un = f"@{bot_username}"
        bw = draw.textlength(bot_un, font=f_med)
        draw.text((W - 15 - bw, y), bot_un, fill=(255, 200, 50), font=f_med)
        y += 30

        # Title
        full_title = "PlayCasino Leaderboard"
        ftw = draw.textlength(full_title, font=f_title)
        title_x = (W - ftw) // 2
        draw.line([(title_x - 60, y + 12), (title_x - 15, y + 12)], fill=(200, 100, 255), width=2)
        draw.text((title_x, y), full_title, fill=(255, 255, 255), font=f_title)
        draw.line([(title_x + ftw + 15, y + 12), (title_x + ftw + 60, y + 12)], fill=(200, 100, 255), width=2)
        y += 42

        # Section title
        draw.rounded_rectangle([20, y, W - 20, y + 34], radius=8, outline=(200, 100, 255), width=2, fill=(35, 15, 50))
        draw.text((40, y + 6), "🏆 Top Referrers", fill=(200, 100, 255), font=f_section)
        y += 44

        # Column headers
        draw.text((50, y), "RANK", fill=(150, 150, 150), font=f_col_header)
        draw.text((110, y), "PLAYER", fill=(150, 150, 150), font=f_col_header)
        draw.text((W - 30, y), "REFERRALS", fill=(150, 150, 150), font=f_col_header, anchor="ra")
        y += 20

        medals = ["\U0001F947", "\U0001F948", "\U0001F949"]
        medal_colors = [(255, 200, 50), (180, 180, 180), (205, 127, 50)]
        medal_nums = ["1", "2", "3"]

        for i, entry in enumerate(entries):
            row_h = 42
            rank = entry["rank"]
            uname = entry["username"]
            if len(uname) > 20:
                uname = uname[:17] + "..."
            ref_count = entry["referrals"]

            if rank == 1:
                row_color = (40, 25, 55)
                draw.rounded_rectangle([20, y, W - 20, y + row_h], radius=10, outline=(200, 100, 255), width=2, fill=row_color)
            elif rank <= 3:
                row_color = (30, 20, 45)
                draw.rounded_rectangle([20, y, W - 20, y + row_h], radius=10, fill=row_color)
            else:
                row_color = (22, 15, 35) if i % 2 == 0 else (18, 12, 30)
                draw.rounded_rectangle([20, y, W - 20, y + row_h], radius=8, fill=row_color)

            if rank <= 3:
                # Draw colored medal circle with number
                mc = medal_colors[rank - 1]
                mx, my = 45, y + 12
                draw.ellipse([mx - 10, my - 10, mx + 10, my + 10], fill=mc, outline=(255, 255, 255), width=1)
                nw = draw.textlength(medal_nums[rank - 1], font=f_reg)
                draw.text((mx - nw // 2, my - 9), medal_nums[rank - 1], fill=(30, 30, 30), font=f_reg)
            else:
                draw.text((38, y + 8), f"#{rank}", fill=(150, 150, 150), font=f_reg)

            draw.text((110, y + 10), uname, fill=(255, 255, 255), font=f_reg)

            val_str = str(ref_count)
            vw = draw.textlength(val_str, font=f_val)
            draw.text((W - 30, y + 10), val_str, fill=(200, 100, 255), font=f_val, anchor="ra")

            y += row_h + 4

        if not entries:
            draw.text((W // 2 - 60, y), "No referrals yet", fill=(150, 150, 150), font=f_reg)
            y += 30

        # Your Rank box
        y += 10
        draw.rounded_rectangle([20, y, W - 20, y + 55], radius=12, outline=(200, 100, 255), width=2, fill=(35, 15, 50))
        draw.rounded_rectangle([35, y + 10, 110, y + 45], radius=8, fill=(50, 20, 60), outline=(200, 100, 255), width=2)
        draw.text((52, y + 13), "#---", fill=(255, 200, 50), font=f_big_rank)
        draw.text((125, y + 10), "Your Rank", fill=(150, 200, 150), font=f_xsmall)
        draw.text((125, y + 28), "0 referrals", fill=(200, 100, 255), font=f_small)

        y += 70
        draw.text(((W - 110) // 2, y), "Play responsibly", fill=(100, 100, 100), font=f_xsmall)

        output = BytesIO()
        img.save(output, format='JPEG', quality=92)
        output.seek(0)
        return output
    except Exception as e:
        logging.error(f"PIL referral leaderboard render error: {e}")
        import traceback
        traceback.print_exc()
        return None


# ============================================================
# GAME RESULT TEMPLATES - Mines, Tower, Keno, Roulette
# ============================================================
# Common game template background helper
def _game_template_background(W=700, H=1050):
    """Create neon bluish-black background with stars."""
    img = Image.new("RGB", (W, H), (8, 14, 28))
    draw = ImageDraw.Draw(img)
    # Subtle gradient overlay
    for y in range(H):
        shade = int(8 + (y / H) * 6)
        draw.line([(0, y), (W, y)], fill=(shade, 14 + int((y/H)*8), 28 + int((y/H)*12)))
    # Stars
    rng = random.Random(99)
    for _ in range(50):
        sx = rng.randint(0, W)
        sy = rng.randint(0, H)
        sr = rng.randint(1, 2)
        draw.ellipse([sx - sr, sy - sr, sx + sr, sy + sr], fill=(100, 180, 255, rng.randint(60, 180)))
    return img, draw


def _render_mines_sync(username, bet_amount, num_mines, picks, mines, won, multiplier, winnings, game_id, safe_count):
    """Render Mines result template showing the 5x5 grid with revealed mines and gems."""
    try:
        W, H = 700, 1050
        img, draw = _game_template_background(W, H)

        try:
            f_title = ImageFont.truetype("bold.ttf", 28)
            f_user = ImageFont.truetype("bold.ttf", 18)
            f_stat = ImageFont.truetype("bold.ttf", 20)
            f_small = ImageFont.truetype("bold.ttf", 12)
            f_result = ImageFont.truetype("bold.ttf", 22)
            f_id = ImageFont.truetype("bold.ttf", 11)
            f_grid_lbl = ImageFont.truetype("bold.ttf", 10)
        except Exception:
            f_title = f_user = f_stat = f_small = f_result = f_id = f_grid_lbl = ImageFont.load_default()

        y = 18

        # Bot username top right
        bot_un = "@playcsino"
        bw = draw.textlength(bot_un, font=f_user)
        draw.text((W - 15 - bw, y), bot_un, fill=(100, 180, 255), font=f_user)
        y += 30

        # Game title
        title = "MINES RESULT"
        tw = draw.textlength(title, font=f_title)
        draw.text(((W - tw) // 2, y), title, fill=(255, 255, 255), font=f_title)
        y += 35

        # Username
        un_bbox = draw.textbbox((0, 0), username, font=f_user)
        un_w = un_bbox[2] - un_bbox[0]
        draw.text(((W - un_w) // 2, y), username, fill=(100, 180, 255), font=f_user)
        y += 30

        # Result banner
        if won:
            banner_color = (0, 60, 40)
            banner_text = f"YOU WON ${winnings:.2f}!"
            banner_fill = (0, 255, 120)
        else:
            banner_color = (60, 10, 10)
            banner_text = "YOU HIT A MINE!"
            banner_fill = (255, 80, 80)

        bw2 = draw.textlength(banner_text, font=f_result)
        draw.rounded_rectangle([(W - bw2 - 40) // 2, y, (W + bw2 + 40) // 2, y + 40], radius=10, fill=banner_color)
        draw.text(((W - bw2) // 2, y + 6), banner_text, fill=banner_fill, font=f_result)
        y += 55

        # Stats row
        stat_y = y
        stats = [
            (f"${bet_amount:.2f}", "BET"),
            (f"{num_mines}", "MINES"),
            (f"{safe_count}", "SAFE PICKS"),
            (f"{multiplier:.2f}x", "MULTIPLIER"),
        ]
        stat_w = 155
        stat_h = 60
        stat_gap = 10
        stat_start = (W - (stat_w * 4 + stat_gap * 3)) // 2
        for i, (val, lbl) in enumerate(stats):
            sx = stat_start + i * (stat_w + stat_gap)
            draw.rounded_rectangle([sx, stat_y, sx + stat_w, stat_y + stat_h], radius=8, fill=(12, 25, 45), outline=(40, 80, 120), width=1)
            draw.text((sx + 10, stat_y + 6), val, fill=(255, 255, 255), font=f_stat)
            draw.text((sx + 10, stat_y + 36), lbl, fill=(100, 160, 200), font=f_grid_lbl)
        y = stat_y + stat_h + 20

        # 5x5 Grid
        grid_size = 5
        cell_size = 90
        grid_gap = 6
        grid_total = grid_size * cell_size + (grid_size - 1) * grid_gap
        grid_x = (W - grid_total) // 2
        grid_y = y

        for row in range(grid_size):
            for col in range(grid_size):
                cell_idx = row * grid_size + col
                cx = grid_x + col * (cell_size + grid_gap)
                cy = grid_y + row * (cell_size + grid_gap)

                # Determine cell state
                is_mine = cell_idx in mines
                is_pick = cell_idx in picks

                if is_pick and is_mine:
                    # Hit mine (red X)
                    bg_color = (80, 15, 15)
                    border = (255, 50, 50)
                    symbol = "💥"
                elif is_pick:
                    # Safe pick (green check)
                    bg_color = (10, 50, 20)
                    border = (50, 200, 80)
                    symbol = "💎"
                elif is_mine:
                    # Revealed mine (orange warning)
                    bg_color = (40, 20, 10)
                    border = (200, 150, 50)
                    symbol = "💣"
                else:
                    # Unrevealed safe
                    bg_color = (10, 18, 35)
                    border = (30, 60, 100)
                    symbol = ""

                draw.rounded_rectangle([cx, cy, cx + cell_size, cy + cell_size], radius=8, fill=bg_color, outline=border, width=2)
                if symbol:
                    try:
                        emoji_font = ImageFont.truetype("NotoColorEmoji.ttf", 36)
                    except Exception:
                        emoji_font = ImageFont.load_default()
                    sym_bbox = draw.textbbox((0, 0), symbol, font=emoji_font)
                    sym_w = sym_bbox[2] - sym_bbox[0]
                    sym_h = sym_bbox[3] - sym_bbox[1]
                    draw.text((cx + (cell_size - sym_w) // 2, cy + (cell_size - sym_h) // 2), symbol, font=emoji_font)

        y = grid_y + grid_total + 25

        # Game ID
        gid_text = f"Game ID: {game_id}"
        gid_w = draw.textlength(gid_text, font=f_id)
        draw.text(((W - gid_w) // 2, y), gid_text, fill=(80, 120, 160), font=f_id)

        output = BytesIO()
        img.save(output, format='PNG')
        output.seek(0)
        return output
    except Exception as e:
        logging.error(f"Mines template render error: {e}")
        return None


def _render_tower_sync(username, bet_amount, difficulty, current_floor, tower_config, selected_tiles, won, multiplier, winnings, game_id):
    """Render Tower result template showing the tower grid with snakes revealed."""
    try:
        W, H = 700, 1050
        img, draw = _game_template_background(W, H)

        try:
            f_title = ImageFont.truetype("bold.ttf", 28)
            f_user = ImageFont.truetype("bold.ttf", 18)
            f_stat = ImageFont.truetype("bold.ttf", 20)
            f_small = ImageFont.truetype("bold.ttf", 12)
            f_result = ImageFont.truetype("bold.ttf", 22)
            f_id = ImageFont.truetype("bold.ttf", 11)
            f_floor = ImageFont.truetype("bold.ttf", 14)
            f_grid_lbl = ImageFont.truetype("bold.ttf", 10)
        except Exception:
            f_title = f_user = f_stat = f_small = f_result = f_id = f_floor = f_grid_lbl = ImageFont.load_default()

        diff_name = {'easy': 'Easy', 'medium': 'Medium', 'hard': 'Hard'}.get(difficulty, difficulty.title())
        tiles_per_floor = {'easy': 4, 'medium': 3, 'hard': 2}.get(difficulty, 3)

        y = 18

        # Bot username
        bot_un = "@playcsino"
        bw = draw.textlength(bot_un, font=f_user)
        draw.text((W - 15 - bw, y), bot_un, fill=(100, 180, 255), font=f_user)
        y += 30

        # Title
        title = f"TOWER - {diff_name}"
        tw = draw.textlength(title, font=f_title)
        draw.text(((W - tw) // 2, y), title, fill=(255, 255, 255), font=f_title)
        y += 35

        # Username
        un_bbox = draw.textbbox((0, 0), username, font=f_user)
        un_w = un_bbox[2] - un_bbox[0]
        draw.text(((W - un_w) // 2, y), username, fill=(100, 180, 255), font=f_user)
        y += 30

        # Result banner
        if won:
            banner_color = (0, 60, 40)
            banner_text = f"TOWER CONQUERED! +${winnings:.2f}"
            banner_fill = (0, 255, 120)
        else:
            banner_color = (60, 10, 10)
            banner_text = "TOWER COLLAPSED!"
            banner_fill = (255, 80, 80)
        bw2 = draw.textlength(banner_text, font=f_result)
        draw.rounded_rectangle([(W - bw2 - 40) // 2, y, (W + bw2 + 40) // 2, y + 40], radius=10, fill=banner_color)
        draw.text(((W - bw2) // 2, y + 6), banner_text, fill=banner_fill, font=f_result)
        y += 55

        # Stats
        stat_y = y
        stats = [
            (f"${bet_amount:.2f}", "BET"),
            (f"{current_floor}/9", "FLOORS"),
            (f"{multiplier:.2f}x" if multiplier > 0 else "0x", "MULTIPLIER"),
        ]
        stat_w = 190
        stat_h = 60
        stat_gap = 10
        stat_start = (W - (stat_w * 3 + stat_gap * 2)) // 2
        for i, (val, lbl) in enumerate(stats):
            sx = stat_start + i * (stat_w + stat_gap)
            draw.rounded_rectangle([sx, stat_y, sx + stat_w, stat_y + stat_h], radius=8, fill=(12, 25, 45), outline=(40, 80, 120), width=1)
            draw.text((sx + 10, stat_y + 6), val, fill=(255, 255, 255), font=f_stat)
            draw.text((sx + 10, stat_y + 36), lbl, fill=(100, 160, 200), font=f_grid_lbl)
        y = stat_y + stat_h + 20

        # Tower grid (9 floors, bottom to top)
        floor_h = 55
        tile_w = 80
        tile_h = 40
        tile_gap = 6
        grid_total_h = 9 * (floor_h + 8)
        grid_start_y = y
        grid_total_w = tiles_per_floor * tile_w + (tiles_per_floor - 1) * tile_gap
        grid_start_x = (W - grid_total_w) // 2

        for floor in range(8, -1, -1):  # Floor 8 at top, floor 0 at bottom
            fy = grid_start_y + (8 - floor) * (floor_h + 8)
            snake_pos = tower_config[floor] if floor < len(tower_config) else -1

            # Floor label
            draw.text((15, fy + 15), f"F{floor + 1}", fill=(100, 160, 200), font=f_floor)

            for tile in range(tiles_per_floor):
                tx = grid_start_x + tile * (tile_w + tile_gap)
                is_snake = (tile == snake_pos)
                is_selected = False
                # Check if this tile was selected on this floor
                # selected_tiles stores floor -> tile mapping
                if floor < len(selected_tiles):
                    is_selected = (selected_tiles[floor] == tile)

                if is_selected and is_snake:
                    bg = (80, 15, 15)
                    border = (255, 50, 50)
                    sym = "💀"
                elif is_selected:
                    bg = (10, 50, 20)
                    border = (50, 200, 80)
                    sym = "✅"
                elif is_snake:
                    bg = (40, 20, 10)
                    border = (200, 150, 50)
                    sym = "🐍"
                else:
                    bg = (10, 18, 35)
                    border = (30, 60, 100)
                    sym = ""

                draw.rounded_rectangle([tx, fy, tx + tile_w, fy + tile_h], radius=6, fill=bg, outline=border, width=2)
                if sym:
                    try:
                        emoji_font = ImageFont.truetype("NotoColorEmoji.ttf", 24)
                    except Exception:
                        emoji_font = ImageFont.load_default()
                    sym_bbox = draw.textbbox((0, 0), sym, font=emoji_font)
                    sym_w = sym_bbox[2] - sym_bbox[0]
                    draw.text((tx + (tile_w - sym_w) // 2, fy + 6), sym, font=emoji_font)

            # Draw snake indicator if not on that floor yet
            if floor >= len(selected_tiles) and not won:
                pass  # unrevealed

        y = grid_start_y + grid_total_h + 20

        # Game ID
        gid_text = f"Game ID: {game_id}"
        gid_w = draw.textlength(gid_text, font=f_id)
        draw.text(((W - gid_w) // 2, y), gid_text, fill=(80, 120, 160), font=f_id)

        output = BytesIO()
        img.save(output, format='PNG')
        output.seek(0)
        return output
    except Exception as e:
        logging.error(f"Tower template render error: {e}")
        return None


