# --- NEW GAME IMPLEMENTATIONS ---

# 1. BLACKJACK GAME
@check_banned
@check_maintenance
async def blackjack_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not is_game_enabled("blackjack"):
        await update.message.reply_text(
            "\U0001f527 <b>Blackjack</b> game is currently under maintenance. Please try again later.",
            parse_mode=ParseMode.HTML
        )
        return
    user = update.effective_user
    args = update.message.text.strip().split()
    await ensure_user_in_wallets(user.id, user.username, context=context)

    user_currency = get_user_currency(user.id)
    formatted_balance = format_currency(get_active_balance_usd(user.id), user_currency)

    if len(args) != 2:
        await update.message.reply_text(f"Usage: /bj amount\nExample: /bj 5 or /bj all\nYour balance: {formatted_balance}")
        return

    try:
        bet_amount_str = args[1]
        bet_amount_usd, bet_amount_currency, currency = parse_bet_amount(bet_amount_str, user.id)
    except ValueError:
        await update.message.reply_text("Invalid amount. Please enter a valid number or 'all'.")
        return

    if not await check_bet_limits(update, bet_amount_usd, 'blackjack'):
        return

    try:
        crypto_deducted, coin = await deduct_wallet_safe(user.id, bet_amount_usd)
    except ValueError:
        await send_insufficient_balance_message(update, f"{pe('cross')} You don't have enough balance. Your balance: {formatted_balance}")
        return
    save_user_data(user.id)

    # Use user's provably fair seeds
    seeds = get_user_seeds(user.id)

    # Create deck and shuffle deterministically using Fisher-Yates
    deck = create_deck()
    for i in range(len(deck) - 1, 0, -1):
        j = get_provably_fair_result(seeds["server_seed"], seeds["client_seed"], seeds["nonce"] + i, i + 1)
        deck[i], deck[j] = deck[j], deck[i]

    player_hand = [deck.pop(), deck.pop()]
    dealer_hand = [deck.pop(), deck.pop()]

    game_id = generate_unique_id("BJ")
    game_sessions[game_id] = {
        "id": game_id,
        "game_type": "blackjack",
        "user_id": user.id,
        "bet_amount": bet_amount_usd,
        "active_currency": get_active_currency(user.id),
        "crypto_bet_amount": bet_amount_usd / LIVE_PRICES.get(get_active_currency(user.id), 1.0),
        "bet_amount_currency": bet_amount_currency,
        "currency": currency,
        "status": "active",
        "timestamp": str(datetime.now(timezone.utc)),
        "deck": deck,
        "player_hand": player_hand,
        "dealer_hand": dealer_hand,
        "server_seed": seeds["server_seed"],
        "client_seed": seeds["client_seed"],
        "nonce": seeds["nonce"],
        "doubled": False
    }
    await ensure_user_in_wallets(user.id, user.username, context=context)
    if 'game_sessions' not in user_stats[user.id]: user_stats[user.id]['game_sessions'] = []
    user_stats[user.id]['game_sessions'].append(game_id)
    save_user_data(user.id)


    player_value = calculate_hand_value(player_hand)
    dealer_show_card = dealer_hand[0]

    hand_text = format_hand("Your hand", player_hand, player_value)
    dealer_text = f"Dealer shows: {dealer_show_card}\n"

    currency_symbol = CURRENCY_SYMBOLS.get(currency, "$")
    formatted_bet = f"{currency_symbol}{bet_amount_currency:.2f}"

    if player_value == 21:
        dealer_value = calculate_hand_value(dealer_hand)
        game_sessions[game_id]['status'] = 'completed'
        game_sessions[game_id]['win'] = True
        increment_user_nonce(user.id)

        # Store provably fair record
        game = game_sessions[game_id]
        store_provably_fair_record(game_id, "blackjack", game["server_seed"], game["client_seed"], game["nonce"],
                                   result_data=f"Player: {player_value}, Dealer: {dealer_value}")

        # Add provably fair button
        keyboard = [[await create_provably_fair_button(game_id, context)]]
        bot_uname = context.bot.username or "Casino"

        if dealer_value == 21:
            credit_wallet(user.id, bet_amount_usd)
            # Push still counts towards leaderboard wagering
            await update_stats_on_bet(user.id, game_id, bet_amount_usd, False, multiplier=0, context=context)
            save_user_data(user.id)
            bj_image = await async_generate_bj_image(
                player_hand=player_hand,
                dealer_hand=dealer_hand,
                show_dealer_hole=True,
                player_value=player_value,
                dealer_value=dealer_value,
                player_username=user.username,
                bet_amount=bet_amount_usd,
                bot_username=bot_uname,
                result_text="Push - Tie",
                result_color=BJ_PUSH_COLOR,
            )
            caption = (
                f"{pe('push')} Push! Both have blackjack. Bet returned: {formatted_bet}\n"
                f"Game ID: <code>{game_id}</code>"
            )
            await update.message.reply_photo(
                photo=bj_image, caption=caption, parse_mode=ParseMode.HTML,
                reply_markup=InlineKeyboardMarkup(keyboard)
            )
        else:
            # Blackjack pays 2.425x (3% house edge)
            winnings_usd = bet_amount_usd * 2.425
            winnings_currency = bet_amount_currency * 2.425
            credit_wallet(user.id, winnings_usd)
            await update_stats_on_bet(user.id, game_id, bet_amount_usd, True, multiplier=2.425, context=context)
            update_pnl(user.id)
            save_user_data(user.id)
            bj_image = await async_generate_bj_image(
                player_hand=player_hand,
                dealer_hand=dealer_hand,
                show_dealer_hole=True,
                player_value=player_value,
                dealer_value=dealer_value,
                player_username=user.username,
                bet_amount=bet_amount_usd,
                bot_username=bot_uname,
                result_text="Blackjack!",
                result_color=BJ_WIN_COLOR,
            )
            caption = (
                f"{pe('win')} Blackjack! You win {currency_symbol}{winnings_currency:.2f}!\n"
                f"Game ID: <code>{game_id}</code>"
            )
            await update.message.reply_photo(
                photo=bj_image, caption=caption, parse_mode=ParseMode.HTML,
                reply_markup=InlineKeyboardMarkup(keyboard)
            )
        return

    # Get bot username for watermark
    bot_uname = context.bot.username or "Casino"

    # Render initial card image
    player_value = calculate_hand_value(player_hand)
    bj_image = await async_generate_bj_image(
        player_hand=player_hand,
        dealer_hand=dealer_hand,
        show_dealer_hole=False,
        player_value=player_value,
        player_username=user.username,
        bet_amount=bet_amount_usd,
        bot_username=bot_uname,
    )

    keyboard_buttons = [
        [InlineKeyboardButton("Hit", callback_data=f"bj_hit_{game_id}"),
         InlineKeyboardButton("Stand", callback_data=f"bj_stand_{game_id}")],
    ]
    if len(player_hand) == 2 and get_active_balance_usd(user.id) >= bet_amount_usd:
        keyboard_buttons.append([InlineKeyboardButton("Double Down", callback_data=f"bj_double_{game_id}")])

    caption = (
        f"{pe('cards')} <b>Blackjack</b> — ID: <code>{game_id}</code>\n"
        f"{pe('money')} Bet: {formatted_bet}"
    )
    sent = await update.message.reply_photo(
        photo=bj_image,
        caption=caption,
        parse_mode=ParseMode.HTML,
        reply_markup=InlineKeyboardMarkup(keyboard_buttons)
    )
    game_sessions[game_id]['message_id'] = sent.message_id
    game_sessions[game_id]['chat_id'] = update.effective_chat.id

# ============================================================
# BLACKJACK CARD IMAGE RENDERER
# Renders a 800x500 casino-table image showing both hands.
# Returns a BytesIO PNG ready to send via Telegram.
# ============================================================
BJ_CARD_W = 78    # card width in pixels
BJ_CARD_H = 110   # card height in pixels
BJ_CARD_RADIUS = 10
BJ_TABLE_COLOR = (14, 80, 40)        # dark casino green
BJ_FELT_LINE   = (20, 100, 52)       # lighter green lines
BJ_CARD_BG     = (255, 255, 255)     # white card face
BJ_CARD_BACK   = (20, 30, 90)        # dark navy card back
BJ_RED         = (204, 0, 0)         # red suits
BJ_BLACK_SUIT  = (15, 15, 15)        # black suits
BJ_TEXT_WHITE  = (255, 255, 255)
BJ_TEXT_GOLD   = (255, 215, 0)
BJ_TEXT_LIGHT  = (200, 230, 200)
BJ_WIN_COLOR   = (50, 220, 100)
BJ_LOSE_COLOR  = (220, 60, 60)
BJ_PUSH_COLOR  = (220, 190, 50)

def _bj_round_rect(draw, bbox, radius, fill, outline=None, outline_width=1):
    """Draw a filled rounded rectangle."""
    x0, y0, x1, y1 = bbox
    draw.rounded_rectangle([x0, y0, x1, y1], radius=radius, fill=fill,
                            outline=outline, width=outline_width)

def _bj_get_font(size: int):
    """Try to load a system font; fall back to default."""
    font_paths = [
        "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
        "/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf",
        "/System/Library/Fonts/Helvetica.ttc",
        "C:/Windows/Fonts/arialbd.ttf",
    ]
    for fp in font_paths:
        try:
            return ImageFont.truetype(fp, size)
        except Exception:
            continue
    return ImageFont.load_default()

def _bj_draw_card(draw, x, y, rank: str, suit: str):
    """Draw a single face-up playing card at position (x, y)."""
    # Card shadow
    draw.rounded_rectangle([x+3, y+3, x+BJ_CARD_W+3, y+BJ_CARD_H+3],
                            radius=BJ_CARD_RADIUS, fill=(0, 0, 0, 80))
    # Card body
    draw.rounded_rectangle([x, y, x+BJ_CARD_W, y+BJ_CARD_H],
                            radius=BJ_CARD_RADIUS, fill=BJ_CARD_BG,
                            outline=(180, 180, 180), width=1)
    color = BJ_RED if suit in ('♥', '♦') else BJ_BLACK_SUIT

    font_rank = _bj_get_font(22)
    font_suit = _bj_get_font(28)
    font_center = _bj_get_font(36)

    # Top-left rank + suit
    draw.text((x+6, y+4), rank, font=font_rank, fill=color)
    draw.text((x+6, y+26), suit, font=font_rank, fill=color)

    # Center suit (large)
    cx = x + BJ_CARD_W // 2
    cy = y + BJ_CARD_H // 2
    suit_w = draw.textlength(suit, font=font_center)
    draw.text((cx - suit_w // 2, cy - 20), suit, font=font_center, fill=color)

    # Bottom-right rank + suit
    draw.text((x + BJ_CARD_W - 22, y + BJ_CARD_H - 42), rank, font=font_rank, fill=color)
    draw.text((x + BJ_CARD_W - 22, y + BJ_CARD_H - 22), suit, font=font_rank, fill=color)

def _bj_draw_hidden_card(draw, x, y):
    """Draw a face-down (hidden) card at position (x, y)."""
    draw.rounded_rectangle([x+3, y+3, x+BJ_CARD_W+3, y+BJ_CARD_H+3],
                            radius=BJ_CARD_RADIUS, fill=(0, 0, 0, 80))
    draw.rounded_rectangle([x, y, x+BJ_CARD_W, y+BJ_CARD_H],
                            radius=BJ_CARD_RADIUS, fill=BJ_CARD_BACK,
                            outline=(80, 80, 160), width=2)
    # Card back pattern (diagonal lines)
    for i in range(-BJ_CARD_H, BJ_CARD_W, 12):
        draw.line([(x + i, y), (x + i + BJ_CARD_H, y + BJ_CARD_H)],
                  fill=(40, 60, 140), width=1)
    # Center logo
    cx, cy = x + BJ_CARD_W // 2, y + BJ_CARD_H // 2
    font = _bj_get_font(20)
    draw.text((cx - 8, cy - 12), "?", font=font, fill=(100, 120, 220))

def _bj_parse_card(card_str: str):
    """Parse card string like 'A♠', '10♥', 'K♦' into (rank, suit)."""
    if len(card_str) >= 2:
        # suit is always the last character
        return card_str[:-1], card_str[-1]
    return card_str, "?"

def generate_bj_image(
    player_hand: list,
    dealer_hand: list,
    show_dealer_hole: bool = False,
    player_value: int = None,
    dealer_value: int = None,
    player_username: str = None,
    bet_amount: float = None,
    bot_username: str = "Casino",
    result_text: str = None,
    result_color: tuple = None,
) -> BytesIO:
    """
    Render a 800x500 blackjack table image.

    - dealer_hand[0] is always shown face-up.
    - dealer_hand[1] is hidden unless show_dealer_hole=True.
    - Additional dealer cards (index 2+) are always shown face-up.
    - Returns a BytesIO PNG buffer.
    """
    W, H = 800, 500
    img = Image.new("RGB", (W, H), BJ_TABLE_COLOR)
    draw = ImageDraw.Draw(img)

    # Background felt texture (subtle grid lines)
    for gx in range(0, W, 40):
        draw.line([(gx, 0), (gx, H)], fill=BJ_FELT_LINE, width=1)
    for gy in range(0, H, 40):
        draw.line([(0, gy), (W, gy)], fill=BJ_FELT_LINE, width=1)

    # Divider line
    draw.line([(30, H // 2), (W - 30, H // 2)], fill=(255, 255, 255, 60), width=2)

    font_label  = _bj_get_font(18)
    font_value  = _bj_get_font(20)
    font_result = _bj_get_font(32)
    font_info   = _bj_get_font(15)
    font_wm     = _bj_get_font(13)

    # DEALER section (top half y=0..249)
    draw.text((40, 14), "DEALER", font=font_label, fill=BJ_TEXT_GOLD)

    # Calculate dealer display value
    if show_dealer_hole:
        d_val_str = f"Value: {dealer_value}" if dealer_value else ""
    else:
        # Only show value of the visible card
        if dealer_hand:
            rank0, _ = _bj_parse_card(dealer_hand[0])
            if rank0 in ('J', 'Q', 'K'):
                visible_val = 10
            elif rank0 == 'A':
                visible_val = 11
            else:
                try:
                    visible_val = int(rank0)
                except ValueError:
                    visible_val = 0
            d_val_str = f"Shows: {visible_val}"
        else:
            d_val_str = ""

    draw.text((40, 35), d_val_str, font=font_value, fill=BJ_TEXT_LIGHT)

    # Draw dealer cards starting x=40, y=62
    dx, dy = 40, 62
    for i, card_str in enumerate(dealer_hand):
        rank, suit = _bj_parse_card(card_str)
        if i == 1 and not show_dealer_hole:
            _bj_draw_hidden_card(draw, dx, dy)
        else:
            _bj_draw_card(draw, dx, dy, rank, suit)
        dx += BJ_CARD_W + 12

    # PLAYER section (bottom half y=250..499)
    draw.text((40, H // 2 + 14), "PLAYER", font=font_label, fill=BJ_TEXT_GOLD)
    p_val_str = f"Value: {player_value}" if player_value else ""
    draw.text((40, H // 2 + 35), p_val_str, font=font_value, fill=BJ_TEXT_LIGHT)

    # Draw player cards
    px, py = 40, H // 2 + 62
    for card_str in player_hand:
        rank, suit = _bj_parse_card(card_str)
        _bj_draw_card(draw, px, py, rank, suit)
        px += BJ_CARD_W + 12

    # Result overlay (if game finished)
    if result_text:
        rc = result_color or BJ_WIN_COLOR
        # Semi-transparent overlay band across center
        overlay = Image.new("RGBA", (W, 60), (*rc, 160))
        img_rgba = img.convert("RGBA")
        img_rgba.paste(overlay, (0, H // 2 - 30), overlay)
        img = img_rgba.convert("RGB")
        draw = ImageDraw.Draw(img)
        rw = draw.textlength(result_text, font=font_result)
        draw.text(((W - rw) // 2, H // 2 - 22), result_text, font=font_result, fill=(255, 255, 255))

    # Bottom info bar
    bar_y = H - 28
    # Left: player name + bet
    left_text = ""
    if player_username:
        left_text += f"@{player_username}"
    if bet_amount is not None:
        left_text += f"  •  Bet: ${bet_amount:.2f}"
    if left_text:
        draw.text((14, bar_y), left_text, font=font_info, fill=BJ_TEXT_LIGHT)

    # Right: bot username watermark
    wm_text = f"@{bot_username}"
    wm_w = draw.textlength(wm_text, font=font_wm)
    draw.text((W - wm_w - 14, bar_y + 2), wm_text, font=font_wm, fill=(120, 180, 120))

    # Save to BytesIO
    buf = BytesIO()
    img.save(buf, format="PNG", optimize=True)
    buf.seek(0)
    return buf

async def async_generate_bj_image(*args, **kwargs) -> BytesIO:
    """Async wrapper for generate_bj_image to avoid blocking the event loop."""
    loop = asyncio.get_event_loop()
    return await loop.run_in_executor(None, lambda: generate_bj_image(*args, **kwargs))


# ============================================================
# LIMBO GAME TEMPLATE IMAGE GENERATOR
# ============================================================

# Limbo color scheme - Neon bluish-black
LIMBO_BG_COLOR = (8, 12, 28)           # Very dark blue-black
LIMBO_ACCENT = (0, 180, 255)            # Neon blue
LIMBO_GREEN = (0, 255, 120)             # Neon green (multiplier)
LIMBO_GOLD = (255, 215, 0)              # Gold text
LIMBO_WIN = (0, 255, 120)               # Win green
LIMBO_LOSE = (255, 60, 60)              # Loss red
LIMBO_TEXT_WHITE = (240, 240, 255)      # Soft white
LIMBO_TEXT_DIM = (140, 160, 200)        # Dim blue-gray
LIMBO_CARD_BG = (15, 25, 50)            # Card background
LIMBO_BORDER = (30, 60, 120)            # Border blue

_limbo_font_cache = {}

def _limbo_get_font(size: int):
    """Load font for Limbo template with caching for performance."""
    if size in _limbo_font_cache:
        return _limbo_font_cache[size]
    
    font_paths = [
        "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
        "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf",
        "/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf",
        "/usr/share/fonts/truetype/liberation/LiberationSans-Regular.ttf",
        "/System/Library/Fonts/Helvetica.ttc",
        "/System/Library/Fonts/Arial.ttf",
        "/usr/share/fonts/TTF/DejaVuSans-Bold.ttf",
        "/usr/share/fonts/TTF/DejaVuSans.ttf",
    ]
    
    try:
        for font_path in font_paths:
            if os.path.exists(font_path):
                font = ImageFont.truetype(font_path, size)
                _limbo_font_cache[size] = font
                return font
    except Exception:
        pass
    
    # Fallback to default
    font = ImageFont.load_default()
    _limbo_font_cache[size] = font
    return font


def generate_limbo_image(
    target_multiplier: float,
    outcome: float,
    bet_amount: float,
    win: bool,
    profit: float = 0.0,
    player_username: str = None,
    bot_username: str = "Casino",
    game_id: str = None,
    currency: str = "USDT",
) -> BytesIO:
    """
    Render a 800x600 Limbo game result image with neon bluish-black theme.
    
    Shows:
    - Target multiplier (top center)
    - Outcome multiplier (center, large)
    - Win/Loss result
    - Player username + bet amount (bottom left)
    - Bot username watermark (bottom right)
    - Game ID (subtle)
    
    Returns a BytesIO PNG buffer.
    """
    W, H = 800, 600
    img = Image.new("RGB", (W, H), LIMBO_BG_COLOR)
    draw = ImageDraw.Draw(img)
    
    # Background gradient effect (subtle radial glow)
    center_x, center_y = W // 2, H // 2 - 40
    for radius in range(200, 0, -10):
        alpha = int(15 * (radius / 200))
        glow_color = (8 + alpha, 12 + alpha // 2, 28 + alpha)
        draw.ellipse(
            [center_x - radius, center_y - radius, center_x + radius, center_y + radius],
            fill=glow_color
        )
    
    # Grid lines (subtle)
    for gx in range(0, W, 50):
        draw.line([(gx, 0), (gx, H)], fill=(20, 35, 70, 40), width=1)
    for gy in range(0, H, 50):
        draw.line([(0, gy), (W, gy)], fill=(20, 35, 70, 40), width=1)
    
    # Top decorative line
    draw.line([(40, 60), (W - 40, 60)], fill=LIMBO_ACCENT, width=2)
    
    # Title: LIMBO
    font_title = _limbo_get_font(28)
    title_text = "LIMBO"
    title_w = draw.textlength(title_text, font=font_title)
    draw.text(((W - title_w) // 2, 18), title_text, font=font_title, fill=LIMBO_ACCENT)
    
    # Game ID (top right, small)
    font_game_id = _limbo_get_font(12)
    if game_id:
        gid_text = f"ID: {game_id}"
        gid_w = draw.textlength(gid_text, font=font_game_id)
        draw.text((W - gid_w - 40, 22), gid_text, font=font_game_id, fill=LIMBO_TEXT_DIM)
    
    # Fonts
    font_label = _limbo_get_font(20)
    font_target = _limbo_get_font(56)
    font_outcome = _limbo_get_font(72)
    font_result = _limbo_get_font(36)
    font_info = _limbo_get_font(18)
    font_small = _limbo_get_font(14)
    font_wm = _limbo_get_font(13)
    
    # TARGET section (top center)
    target_label = "TARGET"
    target_label_w = draw.textlength(target_label, font=font_label)
    draw.text(((W - target_label_w) // 2, 80), target_label, font=font_label, fill=LIMBO_TEXT_DIM)
    
    target_str = f"{target_multiplier:.2f}x"
    target_w = draw.textlength(target_str, font=font_target)
    draw.text(((W - target_w) // 2, 110), target_str, font=font_target, fill=LIMBO_GOLD)
    
    # Divider
    div_y = 190
    draw.line([(100, div_y), (W - 100, div_y)], fill=LIMBO_BORDER, width=1)
    
    # OUTCOME section (center, large)
    outcome_label = "OUTCOME"
    outcome_label_w = draw.textlength(outcome_label, font=font_label)
    draw.text(((W - outcome_label_w) // 2, 210), outcome_label, font=font_label, fill=LIMBO_TEXT_DIM)
    
    outcome_str = f"{outcome:.2f}x"
    outcome_w = draw.textlength(outcome_str, font=font_outcome)
    outcome_color = LIMBO_GREEN if win else LIMBO_LOSE
    draw.text(((W - outcome_w) // 2, 250), outcome_str, font=font_outcome, fill=outcome_color)
    
    # RESULT box (below outcome)
    result_y = 350
    box_h = 80
    box_w = 400
    box_x = (W - box_w) // 2
    
    # Background box
    box_color = LIMBO_WIN if win else LIMBO_LOSE
    # Draw box with rounded corners effect
    draw.rounded_rectangle(
        [box_x, result_y, box_x + box_w, result_y + box_h],
        radius=12,
        fill=(box_color[0] // 5, box_color[1] // 5, box_color[2] // 5),
        outline=box_color,
        width=2
    )
    
    result_text = "YOU WIN!" if win else "YOU LOSE"
    result_w = draw.textlength(result_text, font=font_result)
    draw.text(((W - result_w) // 2, result_y + 8), result_text, font=font_result, fill=box_color)
    
    # Profit/Loss amount
    if win:
        amount_text = f"+${profit:.2f}"
        amount_color = LIMBO_GREEN
    else:
        amount_text = f"-${bet_amount:.2f}"
        amount_color = LIMBO_LOSE
    
    amount_w = draw.textlength(amount_text, font=font_info)
    draw.text(((W - amount_w) // 2, result_y + 50), amount_text, font=font_info, fill=amount_color)
    
    # PAYOUT info (if win)
    if win:
        payout = bet_amount * target_multiplier
        payout_text = f"Payout: ${payout:.2f}"
        payout_w = draw.textlength(payout_text, font=font_small)
        draw.text(((W - payout_w) // 2, result_y + box_h + 12), payout_text, font=font_small, fill=LIMBO_TEXT_DIM)
    
    # Bottom info bar
    bar_y = H - 40
    
    # Left: player username + bet
    left_text = ""
    if player_username:
        left_text += f"@{player_username}"
    left_text += f"  •  Bet: ${bet_amount:.2f} {currency}"
    
    draw.text((20, bar_y), left_text, font=font_info, fill=LIMBO_TEXT_DIM)
    
    # Right: bot username watermark
    wm_text = f"@{bot_username}"
    wm_w = draw.textlength(wm_text, font=font_wm)
    draw.text((W - wm_w - 20, bar_y + 4), wm_text, font=font_wm, fill=(60, 90, 140))
    
    # Side decorative lines
    draw.line([(20, 80), (20, H - 60)], fill=LIMBO_ACCENT, width=1)
    draw.line([(W - 20, 80), (W - 20, H - 60)], fill=LIMBO_ACCENT, width=1)
    
    # Save to BytesIO
    buf = BytesIO()
    img.save(buf, format="PNG", optimize=True)
    buf.seek(0)
    return buf


async def async_generate_limbo_image(*args, **kwargs) -> BytesIO:
    """Async wrapper for generate_limbo_image to avoid blocking the event loop."""
    loop = asyncio.get_event_loop()
    return await loop.run_in_executor(None, lambda: generate_limbo_image(*args, **kwargs))

def create_deck():
    deck = [f"{rank}{suit}" for suit in SUITS for rank in RANKS]
    random.shuffle(deck)
    return deck

def calculate_hand_value(hand):
    value = 0
    aces = 0
    for card in hand:
        rank = card[:-1]
        if rank == 'A':
            aces += 1
            value += 11
        elif rank in ['J', 'Q', 'K']:
            value += 10
        else:
            value += int(rank)
    while value > 21 and aces > 0:
        value -= 10
        aces -= 1
    return value

def format_hand(title, hand, value):
    cards_str = " ".join(hand)
    return f"{title}: {cards_str} (Value: {value})"

@check_banned
@check_maintenance
async def blackjack_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    user = query.from_user

    if not query.data.startswith("bj_"):
        return

    parts = query.data.split("_")
    action = parts[1]
    game_id = parts[2]

    game = game_sessions.get(game_id)

    if not game:
        await query.edit_message_text("Game not found or already finished.")
        return

    # NEW: Game interaction security
    if user.id != game.get('user_id'):
        await query.answer("This is not your game!", show_alert=True)
        return

    if game.get('status') != 'active':
        await query.edit_message_text("This game is already finished.")
        return

    bot_uname = context.bot.username or "Casino"

    if action == "hit":
        card = game["deck"].pop()
        game["player_hand"].append(card)
        player_value = calculate_hand_value(game["player_hand"])

        if player_value > 21:
            game["status"] = 'completed'
            game["win"] = False
            increment_user_nonce(user.id)
            await update_stats_on_bet(user.id, game_id, game["bet_amount"], False, context=context)
            update_pnl(user.id)
            save_user_data(user.id)

            # Store provably fair record
            store_provably_fair_record(game_id, "blackjack", game["server_seed"], game["client_seed"], game["nonce"],
                                       result_data=f"Player busted: {player_value}")

            # Add provably fair button
            keyboard = [[await create_provably_fair_button(game_id, context)]]

            bj_image = await async_generate_bj_image(
                player_hand=game["player_hand"],
                dealer_hand=game["dealer_hand"],
                show_dealer_hole=False,
                player_value=player_value,
                player_username=user.username,
                bet_amount=game["bet_amount"],
                bot_username=bot_uname,
                result_text="Bust!",
                result_color=BJ_LOSE_COLOR,
            )
            caption = (
                f"{pe('bust')} <b>Bust!</b> — ID: <code>{game_id}</code>\n"
                f"You lose {pe('cross')} ${game['bet_amount']:.2f}"
            )
            await query.edit_message_media(
                media=InputMediaPhoto(media=bj_image, caption=caption, parse_mode=ParseMode.HTML),
                reply_markup=InlineKeyboardMarkup(keyboard)
            )
        elif player_value == 21:
            await handle_dealer_turn(query, context, game_id, bot_uname)
        else:
            # Continue game
            bj_image = await async_generate_bj_image(
                player_hand=game["player_hand"],
                dealer_hand=game["dealer_hand"],
                show_dealer_hole=False,
                player_value=player_value,
                player_username=user.username,
                bet_amount=game["bet_amount"],
                bot_username=bot_uname,
            )
            keyboard_buttons = [
                [InlineKeyboardButton("Hit", callback_data=f"bj_hit_{game_id}"),
                 InlineKeyboardButton("Stand", callback_data=f"bj_stand_{game_id}")]
            ]
            caption = (
                f"{pe('cards')} <b>Blackjack</b> — ID: <code>{game_id}</code>\n"
                f"{pe('money')} Bet: ${game['bet_amount']:.2f}"
            )
            await query.edit_message_media(
                media=InputMediaPhoto(media=bj_image, caption=caption, parse_mode=ParseMode.HTML),
                reply_markup=InlineKeyboardMarkup(keyboard_buttons)
            )

    elif action == "stand":
        await handle_dealer_turn(query, context, game_id, bot_uname)

    elif action == "double":
        if get_active_balance_usd(user.id) < game["bet_amount"]:
            # Show alert with deposit option
            await query.answer(f"{pe('cross')} Not enough balance to double down!", show_alert=True)
            # Edit message to show back button
            keyboard = InlineKeyboardMarkup([
                [InlineKeyboardButton("Back to Game", callback_data=f"bj_continue_{game_id}")]
            ])
            await query.edit_message_text(
                f"{pe('cross')} You don't have enough balance to double down.\n\n"
                f"Required: ${game['bet_amount']:.2f}\n"
                f"Your balance: ${get_active_balance_usd(user.id):.2f}\n\n"
                f"Please deposit to continue.",
                reply_markup=keyboard,
                parse_mode=ParseMode.HTML
            )
            return

        deduct_wallet(user.id, game["bet_amount"])
        game["bet_amount"] *= 2
        game["doubled"] = True
        save_user_data(user.id)

        card = game["deck"].pop()
        game["player_hand"].append(card)
        player_value = calculate_hand_value(game["player_hand"])

        if player_value > 21:
            game["status"] = 'completed'
            game["win"] = False
            increment_user_nonce(user.id)
            # On double down loss, the original bet amount is what's recorded for stats
            await update_stats_on_bet(user.id, game_id, game["bet_amount"]/2, False, context=context)
            update_pnl(user.id)
            save_user_data(user.id)

            # Store provably fair record
            store_provably_fair_record(game_id, "blackjack", game["server_seed"], game["client_seed"], game["nonce"],
                                       result_data=f"Double down - Player busted: {player_value}")

            # Add provably fair button
            keyboard = [[await create_provably_fair_button(game_id, context)]]

            bj_image = await async_generate_bj_image(
                player_hand=game["player_hand"],
                dealer_hand=game["dealer_hand"],
                show_dealer_hole=False,
                player_value=player_value,
                player_username=user.username,
                bet_amount=game["bet_amount"],
                bot_username=bot_uname,
                result_text="Bust!",
                result_color=BJ_LOSE_COLOR,
            )
            caption = (
                f"{pe('bust')} <b>Bust! (Doubled Down)</b> — ID: <code>{game_id}</code>\n"
                f"You lose {pe('cross')} ${game['bet_amount']:.2f}"
            )
            await query.edit_message_media(
                media=InputMediaPhoto(media=bj_image, caption=caption, parse_mode=ParseMode.HTML),
                reply_markup=InlineKeyboardMarkup(keyboard)
            )
        else:
            await handle_dealer_turn(query, context, game_id, bot_uname)

async def handle_dealer_turn(query, context, game_id, bot_uname: str = "Casino"):
    game = game_sessions[game_id]
    user_id = game["user_id"]
    original_bet = game["bet_amount"] / 2 if game["doubled"] else game["bet_amount"]
    double_text = " - Doubled Down" if game["doubled"] else ""

    while calculate_hand_value(game["dealer_hand"]) < 17:
        game["dealer_hand"].append(game["deck"].pop())

    player_value = calculate_hand_value(game["player_hand"])
    dealer_value = calculate_hand_value(game["dealer_hand"])

    if dealer_value > 21:
        # Regular win pays 1.94x (3% house edge)
        winnings = game["bet_amount"] * 1.94
        credit_wallet(user_id, winnings)
        result_text_plain = "Dealer Busts! You Win!"
        result_pe_text = f"{pe('win')} Dealer busts! You win ${winnings:.2f}!"
        result_color_tuple = BJ_WIN_COLOR
        game['win'] = True
        await update_stats_on_bet(user_id, game_id, original_bet, True, multiplier=1.94, context=context)
    elif dealer_value > player_value:
        result_text_plain = "Dealer Wins"
        result_pe_text = f"{pe('lose')} Dealer wins with {dealer_value}. You lose ${game['bet_amount']:.2f}"
        result_color_tuple = BJ_LOSE_COLOR
        game['win'] = False
        await update_stats_on_bet(user_id, game_id, original_bet, False, context=context)
    elif player_value > dealer_value:
        # Regular win pays 1.94x (3% house edge)
        winnings = game["bet_amount"] * 1.94
        credit_wallet(user_id, winnings)
        result_text_plain = "You Win!"
        result_pe_text = f"{pe('win')} You win! ${winnings:.2f}"
        result_color_tuple = BJ_WIN_COLOR
        game['win'] = True
        await update_stats_on_bet(user_id, game_id, original_bet, True, multiplier=1.94, context=context)
    else:
        credit_wallet(user_id, game["bet_amount"])
        result_text_plain = "Push - Tie"
        result_pe_text = f"{pe('push')} Push! Bet returned."
        result_color_tuple = BJ_PUSH_COLOR
        game['win'] = None # No win or loss
        # Push still counts towards leaderboard wagering
        await update_stats_on_bet(user_id, game_id, original_bet, False, multiplier=0, context=context)

    update_pnl(user_id)
    save_user_data(user_id)
    game["status"] = 'completed'
    increment_user_nonce(user_id)

    # Store provably fair record
    store_provably_fair_record(game_id, "blackjack", game["server_seed"], game["client_seed"], game["nonce"],
                               result_data=f"Player: {player_value}, Dealer: {dealer_value}")

    # Add provably fair button
    keyboard = [[await create_provably_fair_button(game_id, context)]]

    bj_image = await async_generate_bj_image(
        player_hand=game["player_hand"],
        dealer_hand=game["dealer_hand"],
        show_dealer_hole=True,
        player_value=player_value,
        dealer_value=dealer_value,
        player_username=None,
        bet_amount=game["bet_amount"],
        bot_username=bot_uname,
        result_text=result_text_plain,
        result_color=result_color_tuple,
    )
    caption = (
        f"{pe('cards')} <b>Blackjack{double_text}</b> — ID: <code>{game_id}</code>\n\n"
        f"{result_pe_text}"
    )
    await query.edit_message_media(
        media=InputMediaPhoto(media=bj_image, caption=caption, parse_mode=ParseMode.HTML),
        reply_markup=InlineKeyboardMarkup(keyboard)
    )

